import java.util.Scanner;
import java.nio.charset.StandardCharsets;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Limit the buffer size to prevent buffer overflow
        byte[] buffer = new byte[10];

        // Copy only up to the length of the buffer
        byte[] nameBytes = name.getBytes(StandardCharsets.UTF_8);
        int lengthToCopy = Math.min(nameBytes.length, buffer.length);

        System.arraycopy(nameBytes, 0, buffer, 0, lengthToCopy);

        System.out.println("Hello, " + new String(buffer, StandardCharsets.UTF_8).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
